@Service
class ProductSearchService {

    private static final String PRODUCTS_INDEX = "products";
    private static final String SEARCH_QUERIES_INDEX = "customer_search_queries";

    private final RestHighLevelClient client;

    ProductSearchService(RestHighLevelClient client) {
        this.client = client;
    }

    public void indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }
        Instant now = Instant.now();
        if (product.getCreatedAt() == null) {
            product.setCreatedAt(now.toString());
        }
        product.setUpdatedAt(now.toString());

        IndexRequest request = new IndexRequest(PRODUCTS_INDEX)
                .id(product.getId())
                .source(product.toMap());
        client.index(request, RequestOptions.DEFAULT);
    }

    public void bulkIndexProducts(List<Product> products) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        Instant now = Instant.now();

        for (Product product : products) {
            if (product.getId() == null || product.getId().isBlank()) {
                product.setId(UUID.randomUUID().toString());
            }
            if (product.getCreatedAt() == null) {
                product.setCreatedAt(now.toString());
            }
            product.setUpdatedAt(now.toString());

            bulkRequest.add(new IndexRequest(PRODUCTS_INDEX)
                    .id(product.getId())
                    .source(product.toMap()));
        }

        client.bulk(bulkRequest, RequestOptions.DEFAULT);
    }

    public SearchResult searchProducts(ProductSearchRequest request) throws IOException {
        SearchRequest searchRequest = new SearchRequest(PRODUCTS_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            MultiMatchQueryBuilder textQuery = QueryBuilders.multiMatchQuery(request.getQuery(), "name^3", "description^2", "brand")
                    .type(MultiMatchQueryBuilder.Type.BEST_FIELDS)
                    .fuzziness(Fuzziness.AUTO);
            boolQuery.must(textQuery);
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (request.getCategory() != null && !request.getCategory().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("category", request.getCategory()));
        }

        if (request.getBrand() != null && !request.getBrand().isBlank()) {
            boolQuery.filter(QueryBuilders.termQuery("brand", request.getBrand()));
        }

        if (request.getInStock() != null) {
            boolQuery.filter(QueryBuilders.termQuery("inStock", request.getInStock()));
        }

        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            var rangeQuery = QueryBuilders.rangeQuery("price");
            if (request.getMinPrice() != null) {
                rangeQuery.gte(request.getMinPrice());
            }
            if (request.getMaxPrice() != null) {
                rangeQuery.lte(request.getMaxPrice());
            }
            boolQuery.filter(rangeQuery);
        }

        if (request.getTags() != null && !request.getTags().isEmpty()) {
            boolQuery.filter(QueryBuilders.termsQuery("tags", request.getTags()));
        }

        sourceBuilder.query(boolQuery);
        sourceBuilder.from(Math.max(request.getPage(), 0) * Math.max(request.getSize(), 1));
        sourceBuilder.size(Math.max(request.getSize(), 1));

        sourceBuilder.aggregation(AggregationBuilders.terms("categories").field("category").size(20));
        sourceBuilder.aggregation(AggregationBuilders.terms("brands").field("brand").size(20));
        sourceBuilder.aggregation(
                AggregationBuilders.range("price_ranges").field("price")
                        .addUnboundedTo(50)
                        .addRange(50, 100)
                        .addRange(100, 250)
                        .addRange(250, 500)
                        .addUnboundedFrom(500)
        );

        searchRequest.source(sourceBuilder);
        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<ProductDocument> products = Arrays.stream(response.getHits().getHits())
                .map(this::toProductDocument)
                .collect(Collectors.toList());

        Facets facets = new Facets();

        ParsedStringTerms categoryTerms = response.getAggregations().get("categories");
        if (categoryTerms != null) {
            facets.setCategories(categoryTerms.getBuckets().stream()
                    .map(bucket -> new FacetValue(bucket.getKeyAsString(), bucket.getDocCount()))
                    .collect(Collectors.toList()));
        }

        ParsedStringTerms brandTerms = response.getAggregations().get("brands");
        if (brandTerms != null) {
            facets.setBrands(brandTerms.getBuckets().stream()
                    .map(bucket -> new FacetValue(bucket.getKeyAsString(), bucket.getDocCount()))
                    .collect(Collectors.toList()));
        }

        ParsedRange priceRanges = response.getAggregations().get("price_ranges");
        if (priceRanges != null) {
            facets.setPriceRanges(priceRanges.getBuckets().stream()
                    .map(bucket -> new FacetValue(bucket.getKeyAsString(), bucket.getDocCount()))
                    .collect(Collectors.toList()));
        }

        SearchResult result = new SearchResult();
        result.setProducts(products);
        result.setFacets(facets);
        result.setTotalHits(response.getHits().getTotalHits() != null ? response.getHits().getTotalHits().value : products.size());
        result.setPage(request.getPage());
        result.setSize(request.getSize());

        storeSearchQuery(request, (int) result.getTotalHits());

        return result;
    }

    private void storeSearchQuery(ProductSearchRequest request, int resultCount) throws IOException {
        CustomerSearchQuery query = new CustomerSearchQuery();
        query.setId(UUID.randomUUID().toString());
        query.setQuery(request.getQuery());
        query.setUserId(request.getUserId());
        query.setSessionId(request.getSessionId());
        Map<String, Object> filters = new HashMap<>();
        filters.put("category", request.getCategory());
        filters.put("brand", request.getBrand());
        filters.put("inStock", request.getInStock());
        filters.put("minPrice", request.getMinPrice());
        filters.put("maxPrice", request.getMaxPrice());
        filters.put("tags", request.getTags());
        query.setFilters(filters);
        query.setResultCount(resultCount);
        query.setSearchedAt(Instant.now().toString());

        IndexRequest indexRequest = new IndexRequest(SEARCH_QUERIES_INDEX)
                .id(query.getId())
                .source(query.toMap());

        client.index(indexRequest, RequestOptions.DEFAULT);
    }

    private ProductDocument toProductDocument(SearchHit hit) {
        Map<String, Object> source = hit.getSourceAsMap();
        ProductDocument doc = new ProductDocument();
        doc.setId(asString(source.get("id"), hit.getId()));
        doc.setName(asString(source.get("name"), null));
        doc.setDescription(asString(source.get("description"), null));
        doc.setBrand(asString(source.get("brand"), null));
        doc.setCategory(asString(source.get("category"), null));
        doc.setTags(asStringList(source.get("tags")));
        doc.setPrice(asDouble(source.get("price")));
        doc.setCurrency(asString(source.get("currency"), null));
        doc.setInStock(asBoolean(source.get("inStock")));
        doc.setRating(asFloat(source.get("rating")));
        doc.setAttributes(asMap(source.get("attributes")));
        doc.setCreatedAt(asString(source.get("createdAt"), null));
        doc.setUpdatedAt(asString(source.get("updatedAt"), null));
        return doc;
    }

    private String asString(Object value, String defaultValue) {
        return value != null ? String.valueOf(value) : defaultValue;
    }

    private Double asDouble(Object value) {
        return value != null ? Double.valueOf(String.valueOf(value)) : null;
    }

    private Float asFloat(Object value) {
        return value != null ? Float.valueOf(String.valueOf(value)) : null;
    }

    private Boolean asBoolean(Object value) {
        return value != null ? Boolean.valueOf(String.valueOf(value)) : null;
    }

    @SuppressWarnings("unchecked")
    private Map<String, Object> asMap(Object value) {
        return value instanceof Map ? (Map<String, Object>) value : new HashMap<>();
    }

    @SuppressWarnings("unchecked")
    private List<String> asStringList(Object value) {
        if (value instanceof List) {
            return ((List<Object>) value).stream().map(String::valueOf).collect(Collectors.toList());
        }
        return new ArrayList<>();
    }

    @PreDestroy
    public void close() throws IOException {
        client.close();
    }
}

@RestController
@RequestMapping("/api/products")
class ProductController {

    private final ProductSearchService productSearchService;

    ProductController(ProductSearchService productSearchService) {
        this.productSearchService = productSearchService;
    }

    @PostMapping
    public ResponseEntity<Map<String, Object>> indexProduct(@RequestBody Product product) throws IOException {
        productSearchService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(Map.of("message", "Product indexed", "id", product.getId()));
    }

    @PostMapping("/bulk")
    public ResponseEntity<Map<String, Object>> bulkIndexProducts(@RequestBody List<Product> products) throws IOException {
        productSearchService.bulkIndexProducts(products);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(Map.of("message", "Products indexed", "count", products.size()));
    }

    @PostMapping("/search")
    public ResponseEntity<SearchResult> search(@RequestBody ProductSearchRequest request) throws IOException {
        if (request.getPage() < 0) {
            request.setPage(0);
        }
        if (request.getSize() <= 0) {
            request.setSize(10);
        }
        return ResponseEntity.ok(productSearchService.searchProducts(request));
    }
}

